        {q:"Foreign trade creates __ for domestic producers:",opts:["Less competition only","More competition and also new markets abroad","Only problems","Only opportunities"],ans:1},
        {q:"The process of removing trade barriers is called:",opts:["Protection","Liberalisation of trade","Tariff","Quota"],ans:1},
        {q:"Which industry in India BENEFITED most from globalisation?",opts:["Small-scale industries","IT and software services industry","Handloom industry","Farming"],ans:1},
        {q:"'Race to the bottom' refers to:",opts:["Countries competing for lowest corruption","Countries competing to attract MNCs by lowering labour and environmental standards","Stock market falling","Economic recession"],ans:1},
        {q:"India's economic liberalisation began in:",opts:["1947","1971","1991","2001"],ans:2}
